{
    "level": "A2–B1",
    "intro": "In this topic, you will learn how to <strong>correctly choose between comparative and superlative</strong> depending on the context and the number of objects of comparison.",
    "rules": [
        {
            "label": "COMPARATIVE",
            "color": "blue",
            "text": "<strong>Comparison of two</strong> - use with <em>than</em>:",
            "example": "This car is faster than that one."
        },
        {
            "label": "SUPERLATIVE",
            "color": "rose",
            "text": "<strong>Selecting from a group</strong> - use with <em>the</em>:",
            "example": "This is the fastest car in the race."
        },
        {
            "label": "KEY DIFFERENCE",
            "color": "emerald",
            "text": "<strong>The number of objects</strong> determines the choice:",
            "example": "2 objects → comparative; 3+ objects → superlative"
        }
    ]
}

{
    "title": "1. The main difference in use",
    "intro": "The main difference between comparative and superlative is the <strong>number of objects</strong> being compared:",
    "rows": [
        {
            "en": "Comparative",
            "ua": "Comparative",
            "note": "Comparison of TWO objects/persons → -er / more ... than"
        },
        {
            "en": "Superlative",
            "ua": "Superlative",
            "note": "Selection of ONE from the group (3+) → -est / the most"
        },
        {
            "en": "Tom is taller than John.",
            "ua": "Tom is taller than John.",
            "note": "✓ comparative — two objects (Tom and John)"
        },
        {
            "en": "Tom is the tallest in the class.",
            "ua": "Tom is the tallest in the class.",
            "note": "✓ superlative — one of the group (the whole class)"
        }
    ],
    "warning": "💡 Remember: <strong>two objects = comparative</strong>, <strong>three+ objects = superlative</strong>."
}

{
    "title": "2. When to use Comparative",
    "sections": [
        {
            "label": "A direct comparison of the two",
            "color": "blue",
            "description": "Use <strong>comparative</strong> when comparing <strong>two specific things</strong>:",
            "examples": [
                {
                    "en": "My house is bigger than your house.",
                    "ua": "My house is bigger than your house."
                },
                {
                    "en": "She is more intelligent than her brother.",
                    "ua": "She is more intelligent than her brother."
                },
                {
                    "en": "Today is colder than yesterday.",
                    "ua": "Today is colder than yesterday."
                }
            ]
        },
        {
            "label": "Comparison with \"than\"",
            "color": "sky",
            "description": "The <strong>than</strong> marker almost always indicates the need for a comparative:",
            "examples": [
                {
                    "en": "This book is more interesting than the previous one.",
                    "ua": "This book is more interesting than the previous one."
                },
                {
                    "en": "He runs faster than anyone I know.",
                    "ua": "He runs faster than anyone I know."
                },
                {
                    "en": "It's better than I expected.",
                    "ua": "It's better than I expected."
                }
            ]
        },
        {
            "label": "General comparison",
            "color": "emerald",
            "description": "Even without the explicit \"than\" when comparing two states:",
            "examples": [
                {
                    "en": "I feel better today. (ніж вчора)",
                    "ua": "I feel better today. (ніж вчора)"
                },
                {
                    "en": "Can you speak louder? (ніж зараз)",
                    "ua": "Can you speak louder? (ніж зараз)"
                },
                {
                    "en": "This method is more effective. (ніж інший)",
                    "ua": "This method is more effective. (ніж інший)"
                }
            ]
        }
    ]
}

{
    "title": "3. When to use the Superlative",
    "sections": [
        {
            "label": "Selection from the group",
            "color": "rose",
            "description": "Use the <strong>superlative</strong> when you highlight <strong>one object among many</strong>:",
            "examples": [
                {
                    "en": "He is the tallest student in the class.",
                    "ua": "He is the tallest student in the class."
                },
                {
                    "en": "This is the most expensive car in the showroom.",
                    "ua": "This is the most expensive car in the showroom."
                },
                {
                    "en": "She is the smartest person I know.",
                    "ua": "She is the smartest person I know."
                }
            ]
        },
        {
            "label": "Using \"the\"",
            "color": "amber",
            "description": "The <strong>the</strong> marker before an adjective almost always indicates a superlative:",
            "examples": [
                {
                    "en": "Mount Everest is the highest mountain in the world.",
                    "ua": "Mount Everest is the highest mountain in the world."
                },
                {
                    "en": "This is the best pizza I've ever had.",
                    "ua": "This is the best pizza I've ever had."
                },
                {
                    "en": "She chose the cheapest option.",
                    "ua": "She chose the cheapest option."
                }
            ]
        },
        {
            "label": "With prepositions in/of",
            "color": "sky",
            "description": "The superlative often comes with <strong>in</strong> (place/group) or <strong>of</strong> (set):",
            "examples": [
                {
                    "en": "He is the fastest runner in the team.",
                    "ua": "He is the fastest runner in the team."
                },
                {
                    "en": "This is the oldest of all the buildings.",
                    "ua": "This is the oldest of all the buildings."
                },
                {
                    "en": "She is the youngest in her family.",
                    "ua": "She is the youngest in her family."
                }
            ]
        }
    ]
}

{
    "title": "4. Visual rule of choice",
    "intro": "A simple algorithm for choosing between comparative and superlative:",
    "items": [
        {
            "label": "Step 1",
            "title": "How many objects?",
            "subtitle": "2 objects → Comparative; 3+ objects → Superlative"
        },
        {
            "label": "Step 2",
            "title": "Look for markers",
            "subtitle": "than = Comparative; the = Superlative"
        },
        {
            "label": "Step 3",
            "title": "The context of the comparison",
            "subtitle": "Direct comparison → Comparative; Highlight → Superlative"
        },
        {
            "label": "Step 4",
            "title": "Check the prepositions",
            "subtitle": "in/of after adjective → probably Superlative"
        }
    ]
}

{
    "title": "5. Comparison of constructions",
    "intro": "Parallel examples to better understand the difference:",
    "rows": [
        {
            "en": "Paris is bigger than Lyon.",
            "ua": "Paris is bigger than Lyon.",
            "note": "✓ comparative — two cities"
        },
        {
            "en": "Paris is the biggest city in France.",
            "ua": "Paris is the biggest city in France.",
            "note": "✓ superlative is one of many cities"
        },
        {
            "en": "This exam was harder than the last one.",
            "ua": "This exam was harder than the last one.",
            "note": "✓ comparative — two exams"
        },
        {
            "en": "This was the hardest exam of the year.",
            "ua": "This was the hardest exam of the year.",
            "note": "✓ superlative — one of all exams of the year"
        },
        {
            "en": "She is more experienced than me.",
            "ua": "She is more experienced than me.",
            "note": "✓ comparative — two persons"
        },
        {
            "en": "She is the most experienced in our team.",
            "ua": "She is the most experienced in our team.",
            "note": "✓ superlative is one of the team"
        }
    ],
    "warning": "💡 Pay attention to the markers: <strong>than</strong> for comparative, <strong>the</strong> for superlative."
}

{
    "title": "6. Typical mistakes of Ukrainian speakers",
    "sections": [
        {
            "label": "Mistake 1: Confusion with \"the\"",
            "color": "rose",
            "description": "Using <strong>the</strong> with the comparative or omitting it with the superlative:",
            "examples": [
                {
                    "en": "❌ He is the taller than me. → ✓ He is taller than me.",
                    "ua": "❌ He is the taller than me. → ✓ He is taller than me."
                },
                {
                    "en": "❌ She is most beautiful girl. → ✓ She is the most beautiful girl.",
                    "ua": "❌ She is most beautiful girl. → ✓ She is the most beautiful girl."
                },
                {
                    "en": "❌ This is more better. → ✓ This is better.",
                    "ua": "❌ This is more better. → ✓ This is better."
                }
            ]
        },
        {
            "label": "Mistake 2: Wrong choice",
            "color": "amber",
            "description": "Using comparative instead of superlative and vice versa:",
            "examples": [
                {
                    "en": "❌ She is the taller of two sisters. → ✓ She is the taller of the two.",
                    "ua": "❌ She is the taller of two sisters. → ✓ She is the taller of the two."
                },
                {
                    "en": "❌ He is taller in the class. → ✓ He is the tallest in the class.",
                    "ua": "❌ He is taller in the class. → ✓ He is the tallest in the class."
                },
                {
                    "en": "❌ This is the better than that. → ✓ This is better than that.",
                    "ua": "❌ This is the better than that. → ✓ This is better than that."
                }
            ]
        },
        {
            "label": "Mistake 3: Omitting \"than\"",
            "color": "sky",
            "description": "Forgetting <strong>than</strong> after comparative when comparing:",
            "examples": [
                {
                    "en": "❌ My car is faster your car. → ✓ My car is faster than yours.",
                    "ua": "❌ My car is faster your car. → ✓ My car is faster than yours."
                },
                {
                    "en": "❌ She is more intelligent him. → ✓ She is more intelligent than him.",
                    "ua": "❌ She is more intelligent him. → ✓ She is more intelligent than him."
                }
            ]
        }
    ]
}

{
    "title": "7. Special cases",
    "sections": [
        {
            "label": "Comparing the two: can be superlative!",
            "color": "emerald",
            "description": "With <strong>of the two</strong> you can use the superlative to emphasize:",
            "examples": [
                {
                    "en": "She is the taller of the two sisters.",
                    "ua": "She is the taller of the two sisters."
                },
                {
                    "en": "She is taller than her sister.",
                    "ua": "She is taller than her sister."
                },
                {
                    "en": "This is the better of the two options.",
                    "ua": "This is the better of the two options."
                }
            ]
        },
        {
            "label": "Comparison with yourself",
            "color": "blue",
            "description": "Comparative is used to compare <strong>different states of the same thing</strong>:",
            "examples": [
                {
                    "en": "The weather is getting colder.",
                    "ua": "The weather is getting colder."
                },
                {
                    "en": "I'm feeling better now.",
                    "ua": "I'm feeling better now."
                },
                {
                    "en": "Life is more complicated than before.",
                    "ua": "Life is more complicated than before."
                }
            ]
        },
        {
            "label": "Absolute superlative",
            "color": "rose",
            "description": "Sometimes the superlative is used <strong>without a group</strong> to emphasize:",
            "examples": [
                {
                    "en": "You are the best! (взагалі, не в групі)",
                    "ua": "You are the best! (взагалі, не в групі)"
                },
                {
                    "en": "This is the worst! (емоційно)",
                    "ua": "This is the worst! (емоційно)"
                },
                {
                    "en": "Have a most wonderful day! (дуже ввічливо)",
                    "ua": "Have a most wonderful day! (дуже ввічливо)"
                }
            ]
        }
    ]
}

{
    "title": "8. Checklist for inspection",
    "items": [
        {
            "label": "Check 1",
            "color": "emerald",
            "title": "How many objects are compared?",
            "wrong": "Два об'єкти?",
            "right": "→ Використовуй <strong>comparative</strong>"
        },
        {
            "label": "Check 2",
            "color": "blue",
            "title": "Is the word \"than\" in the sentence?",
            "wrong": "Так, є \"than\"",
            "right": "→ Використовуй <strong>comparative</strong>"
        },
        {
            "label": "Check 3",
            "color": "rose",
            "title": "Do you single out one of the group?",
            "wrong": "Так, один з багатьох",
            "right": "→ Використовуй <strong>the + superlative</strong>"
        },
        {
            "label": "Check 4",
            "color": "amber",
            "title": "Is there \"in/of\" after the adjective?",
            "wrong": "Так, є in/of",
            "right": "→ Швидше за все <strong>superlative</strong>"
        }
    ]
}

{
    "title": "Other pages from the category Adjectives and adverbs",
    "items": [
        {
            "label": "Degrees of Comparison",
            "url": "/theory/adjectives/theory-degrees-of-comparison"
        },
        {
            "label": "Adjectives vs Adverbs",
            "url": "/theory/adjectives/adjectives-vs-adverbs"
        }
    ]
}
